& { $path = "$env:downloads"; $files = Get-ChildItem -Path $path -Recurse -File -ErrorAction SilentlyContinue; $folders = Get-ChildItem -Path $path -Recurse -Directory -ErrorAction SilentlyContinue; $totalSize = ($files | Measure-Object -Property Length -Sum).Sum; $sizeMB = [math]::Round($totalSize / 1MB, 2); $sizeGB = [math]::Round($totalSize / 1GB, 2); Write-Host 'Location: ' -NoNewline; Write-Host $path -ForegroundColor Cyan; Write-Host 'Files: ' -NoNewline; Write-Host ($files.Count) -ForegroundColor Yellow; Write-Host 'Folders: ' -NoNewline; Write-Host ($folders.Count) -ForegroundColor Yellow; if ($sizeGB -gt 1) { Write-Host 'Total Size: ' -NoNewline; Write-Host $sizeGB -ForegroundColor Red -NoNewline; Write-Host ' GB' } else { Write-Host 'Total Size: ' -NoNewline; Write-Host $sizeMB -ForegroundColor Yellow -NoNewline; Write-Host ' MB' } }
